// Extract message text and chat ID from Telegram update
const msg = items[0].json;

const chatId  = msg?.message?.chat?.id || msg?.chat?.id || null;
const text    = msg?.message?.text   || msg?.text   || '';
const from    = msg?.message?.from?.first_name || 'User';

if (!chatId || !text) {
  return [{ json: { chatId: null, text: '', from: '', skip: true } }];
}

return [{ json: { chatId, text, from, skip: false } }];

// Parse the backend response and format for Telegram
const data = items[0].json;
const chatId = $('Extract Message').item.json.chatId;

const reply  = data?.reply  || '🤔 Sorry, I did not understand that.';
const action = data?.action_taken || 'none';
const extra  = data?.data   || null;

let finalMessage = reply;

// If summary — add a formatted block
if (action === 'get_summary' && extra) {
  finalMessage = [
    reply,
    '',
    '```',
    `Period    : ${extra.period}`,
    `Sales     : ${extra.total_sales}`,
    `Expenses  : ${extra.total_expenses}`,
    `Profit    : ${extra.profit}`,
    `Txn Count : ${extra.transaction_count}`,
    '```'
  ].join('\n');
}

// If transactions — format as list
if (action === 'get_transactions' && extra?.transactions?.length) {
  const lines = extra.transactions.slice(0, 5).map(t =>
    `• ${t.type.toUpperCase()} — ${t.amount} (${t.category}) — ${t.date.slice(0,10)}`
  );
  finalMessage = reply + '\n' + lines.join('\n');
}

return [{ json: { chatId, finalMessage } }];
